import subprocess
import os

def generate_requirements_txt_with_hashes():
    """Generate a requirements.txt file with hashes using pip."""
    subprocess.run(["pip", "freeze", "--all", "--hash"], stdout=open("requirements.txt", "w"))

def update_requirements_txt_with_hashes():
    """Update the existing requirements.txt file with the latest hashes."""
    subprocess.run(["pip-compile", "--generate-hashes"])

def generate_poetry_lock_file():
    """Generate or update a Poetry lock file."""
    subprocess.run(["poetry", "lock"])

def main():
    # Choose the dependency management tool you are using
    use_pip = True  # Set to False if using Poetry

    if use_pip:
        print("Using pip for dependency management.")
        generate_requirements_txt_with_hashes()
        update_requirements_txt_with_hashes()
    else:
        print("Using Poetry for dependency management.")
        generate_poetry_lock_file()

if __name__ == "__main__":
    main()